1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: string; items: Item[] };
13	type Input = { steps: Step[] };
14	
15	const itemPremium = (item: Item): number => {
16	  const base = BASE_PREMIUMS[item.type] ?? 0;
17	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
18	  return base + firstInsuranceSurcharge;
19	};
20	
21	const quotePremium = (step: Step): number => {
22	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
23	  return Math.ceil(itemsTotal) + PROCESSING_FEE;
24	};
25	
26	export const runScenario = (input: unknown): unknown => {
27	  const { steps } = input as Input;
28	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
29	  return { results };
30	};
